pub enum ThreadStateView {
    Map { vaddr: nat, pte: <PTE as View>::V },
    Unmap { vaddr: nat, pte: Option<<PTE as View>::V> },
    Idle,
}

impl View for ThreadState {
    type V = ThreadStateView;
    closed spec fn view(&self) -> ThreadStateView {
        match self {
            ThreadState::Map { vaddr, pte } => ThreadStateView::Map { vaddr: *vaddr, pte: pte@ },
            ThreadState::Unmap { vaddr, pte } => ThreadStateView::Unmap { vaddr: *vaddr, pte: pte@ },
            ThreadState::Idle => ThreadStateView::Idle,
        }
    }
}

